<template>
  <section>
    <loader :is-visible="isLoading"></loader>
    
    <tg-list 
      :IsShowAction="true" 
      ModuleName="RateSchedule" 
      SubModuleCode="" 
      :LegendArray="[]"
      :RenderRowActionMethod="renderActions" 
      @ActionButtonClick="actionButtonClick" 
      :widgets="[]"
      IdentityColumn="RATE_SCHEDULE_ID" 
      :listType="['List']" 
      :ListData="RateScheduleData" 
      :HeaderData="Headers"
      :HeaderButtons="listheaderbuttons" 
      :TotalRecords="TotalRecords" 
      :SearchFields="leftSearchFields"
      IsSearchFieldsOnTop="true" 
      :ListDataCallBackFunction="FetchData" 
      :showCheckBox="true"
      :SortExp="SortExp" 
      :SortBy="SortBy" 
      :NorecordfoundText="$t('NoRecordfound')" 
      :HeaderText="$t('RateSchedule')"
      @LeftsearchButtonClick="leftCommonSearch" 
      @PagerButtonClick="pagerMethod"
      @HeaderButtonClick="commonHeaderButtonClick" 
      @SortdataButtonClick="sortdata" 
      :routeInfo="$router"
    >
      <template v-slot:slotdata="{ data }">
        <!-- CREATED_AT Column -->
        <template v-if="data.column.COLUMN_NAME === 'CREATED_AT'">
          <span>
            {{ $options.filters.formatDateTime(data.row.CREATED_AT) }}
          </span>
        </template>
        
        <!-- MODIFIED_AT Column -->
        <template v-if="data.column.COLUMN_NAME === 'MODIFIED_AT'">
          <span>
            {{ $options.filters.formatDateTime(data.row.MODIFIED_AT) }}
          </span>
        </template>
        
        <!-- STATUS Column -->
        <template v-if="data.column.COLUMN_NAME === 'STATUS'">
          <td class="text-center single-action">
            <div class="cstm-drop-btn">
              <select 
                v-model="data.row.STATUS_ID" 
                @change="UpdataStatus(data.row.STATUS_ID, data.row.RATE_SCHEDULE_ID)"
                :class="[
                  'ddlupdatestatus w-80', 
                  data.row.STATUS_ID == 1001 ? 'btn-success' : 'btn-danger'
                ]"
              >
                <option value="1001">{{ $t("Active") }}</option>
                <option value="1002">{{ $t("Inactive") }}</option>
              </select>
            </div>
          </td>
        </template>
        
        <!-- Billing_Code Column -->
        <template v-if="data.column.COLUMN_NAME === 'Billing_Code'">
          <div v-if="isCopy" class="input-group mb-3">
            <input 
              class="form-control" 
              v-model="data.row.Billing_Code"
            />
          </div>
          <span v-else>
            <div class="text">
              <span :title="data.row.Billing_Code">{{ data.row.Billing_Code }}</span>
            </div>
          </span>
        </template>
        
        <!-- AMOUNT Column -->
        <template v-if="data.column.COLUMN_NAME === 'AMOUNT'">
          <div v-if="isCopy" class="input-group mb-3">
            <input 
              class="form-control" 
              v-model="data.row.AMOUNT"
            />
          </div>
          <span v-else>
            <div class="text">
              <span :title="data.row.AMOUNT">{{ data.row.AMOUNT }}</span>
            </div>
          </span>
        </template>
        
        <!-- START_DATE Column -->
        <template v-if="data.column.COLUMN_NAME === 'START_DATE'">
          <div v-if="isCopy" class="input-group mb-3">
            <input 
              class="form-control" 
              v-model="data.row.START_DATE" 
              disabled
            />
          </div>
          <span v-else>
            <div class="text">
              <span :title="data.row.START_DATE">{{ data.row.START_DATE }}</span>
            </div>
          </span>
        </template>
        
        <!-- END_DATE Column -->
        <template v-if="data.column.COLUMN_NAME === 'END_DATE'">
          <div v-if="isCopy" class="input-group mb-3">
            <input 
              class="form-control" 
              v-model="data.row.END_DATE" 
              disabled
            />
          </div>
          <span v-else>
            <div class="text">
              <span :title="data.row.END_DATE">{{ data.row.END_DATE }}</span>
            </div>
          </span>
        </template>
        
        <!-- New_Start_Date Column -->
        <template v-if="data.column.COLUMN_NAME === 'New_Start_Date'">
          <input
            type="text"
            class="form-control form-control-sm large-input"
            :value="data.row.New_Start_Date || ''"
            readonly
          />
        </template>
        
        <!-- New_End_Date Column -->
        <template v-if="data.column.COLUMN_NAME === 'New_End_Date'">
          <input
            type="text"
            class="form-control form-control-sm large-input"
            :value="data.row.New_End_Date || ''"
            readonly
          />
        </template>
        
        <!-- New_Rate Column -->
        <template v-if="data.column.COLUMN_NAME === 'New_Rate'">
          <input
            type="number"
            class="form-control form-control-sm large-input"
            v-model.number="data.row.New_Rate"
            min="0"
            step="0.01"
          />
        </template>
        
        <!-- New_Customer_Work_Code Column -->
        <template v-if="data.column.COLUMN_NAME === 'New_Customer_Work_Code'">
          <input
            type="number"
            class="form-control form-control-sm large-input"
            v-model.number="data.row.New_Customer_Work_Code"
            min="0"
            step="0.01"
          />
        </template>
      </template>
    </tg-list>
     <div class="float-right mt-2" v-show="isShownCopyButton ">
            <button class="btn btn-success mr-2" @click="UpdateCopyRateSchedule" >
                <em class="fa fa-save pr-2"></em>
                {{ $t('update Rate Schedule') }}
            </button>
            <button class="btn btn-danger" @click="Cancel">
                {{ $t('Cancel') }}
            </button>
        </div>
    <!-- Dynamic Form -->
    <dynamic-form 
      v-if="isCopy || UpdateRecord" 
      ref="Copy" 
      lang="en" 
      :buttons="buttons" 
      :schema="FormSchema" 
      @OnSubmit="onSubmit"
    />
    
    <!-- Modals/Components -->
    <AddRate v-if="isShowAddRate" :EditData="EditData" />
    <BulkUpdateRate v-if="isBulkUpdateRate" :EditData="EditData" />
    <Copy 
      v-if="isCopyRate" 
      :EditData="EditData" 
      @navigateToSelected="openSelectedRecords" 
      :isCopy="isCopy" 
      :EditDataCopy="EditDataCopy" 
    />
  </section>
</template>

<script>
import AddRate from "./AddRate.vue";
import BulkUpdateRate from "./BulkUpdateRate.vue";
import Copy from "./Copy.vue";
import Schema from "../RateSchedule/Schema.js";
import DataService from "../../services/DataService.js";
import { locateBillingService } from "../../services/locateBillingService";
import * as XLSX from 'xlsx';
import moment from 'moment';

export default {
    components: {
        AddRate,
        BulkUpdateRate,
        Copy
    },
    data() {
        return {
            isLoading: false,
            isCopyRate: false,
            key:0,
            isCopy: false,
            UpdateRecord: false,
            FormSchema: [],
            buttons: [{
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Update Rate Schedule",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.FetchData
                }
            ],
            Headers: [{
                    "COLUMN_NAME": "CLIENT_NAME",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Contract',
                    "DISPLAY_ORDER": 1,                    
                },
                {
                    "COLUMN_NAME": "WORK_CODE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Work Code',
                    "DISPLAY_ORDER": 2,
                },
                {
                    "COLUMN_NAME": "UTILITY_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Utility Name',
                    "DISPLAY_ORDER": 3,
                },
                {
                    "COLUMN_NAME": "STATE_NAME",
                    "DATA_TYPE": "Date",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'State',
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: false
                    }
                },
                {
                    "COLUMN_NAME": "Billing_Code",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Customer Work Code',
                    "DISPLAY_ORDER": 5,
                    settings: {
                        isInSlot: true
                    }
                },
                 {
                    "COLUMN_NAME": "AMOUNT",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Rate',
                    "DISPLAY_ORDER": 6,
                    settings: {
                        isInSlot: true
                    }
                },
                 {
                    "COLUMN_NAME": "STATUS",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Status',
                    "DISPLAY_ORDER": 7,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "START_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Start Date',
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "END_DATE",
                    "DATA_TYPE": "text",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'End Date',
                    "DISPLAY_ORDER": 9,
                    settings: {
                        isInSlot: true
                    }
                },
                  {
                    "COLUMN_NAME": "New_Customer_Work_Code",
                    "DATA_TYPE": "string",
                   "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New Customer Work Code'),
                    "DISPLAY_ORDER": 10,
                    settings: {
                        isInSlot: true
                    }
                },
                    {
                    "COLUMN_NAME": "New_Rate",
                    "DATA_TYPE": "string",
                   "SORTABLE": false,
                    "VISIBLE": false,
                   "DISPLAY_NAME": this.$t('New Rate'),
                    "DISPLAY_ORDER": 11,
                    settings: {
                        isInSlot: true
                    }
                },
                 {
                    "COLUMN_NAME": "New_Start_Date",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New Start Date'),
                    "DISPLAY_ORDER": 12,
                    settings: {
                        isInSlot: true
                    }
                },
                                {
                    "COLUMN_NAME": "New_End_Date",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": false,
                    "DISPLAY_NAME": this.$t('New End Date'),
                    "DISPLAY_ORDER": 13,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "CREATED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Created AT',
                    "DISPLAY_ORDER": 10,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "CREATED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Created By',
                    "DISPLAY_ORDER": 11,
                },
                {
                    "COLUMN_NAME": "MODIFIED_BY",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified By',
                    "DISPLAY_ORDER": 12,
                },
                {
                    "COLUMN_NAME": "MODIFIED_AT",
                    "DATA_TYPE": "text",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": 'Modified Date',
                    "DISPLAY_ORDER": 13,
                    settings: {
                        isInSlot: true
                    }
                }
            ],
            SortBy: '',
            SortExp: '',
            PageSize: 10,
            PageNumber: 1,
            TotalRecords: 0,
            CurrentPage: 1,
            TotalPages: 0,
            noRecords: false,
            searchCondition: '',
            RateScheduleData: [],
            listheaderbuttons: Schema.buttons,
            listActions: Schema.listActions,
            leftSearchFields: Schema.leftsearchSchema,
            CompanyId: null,
            UserId: null,
            searchBy: '',
            search: '',
            isShowAddRate: false,
            isBulkUpdateRate: false,            
            EditData:[],
            EditDataCopy:[],
            clientId:'',
            clientList:[],
            SelectedUtilityList:[],
            Searchparms:'',
            isSupervisor:false
        }
    },
    created: async function () {
        var vm = this;
        vm.isCopy=false;
        vm.UpdateRecord=false;
        vm.UserType=vm.GetUserInfo.UserType;
        vm.CompanyId = this.GetUserInfo.CompanyId;
        vm.UserId = this.GetUserInfo.ID;
        await vm.BindSupervisor();
        await vm.GetEmailConfigurationSetting();       
        vm.leftSearchFields.find(f => f.fieldName === 'Contract').onChange = this.onSelectionChange;
        await vm.fetchclientlist();
        Schema.bindleftCommonSearchdropdown(this,'WORKCODE');
        Schema.bindleftCommonSearchdropdown(this,'STATE');
        Schema.bindleftCommonSearchdropdown(this,"BILLER");        
        await vm.FetchData(); 
           
    },
    methods: {
          fetchclientlist: async function () { 
            var vm = this;
            vm.isLoading = true;
            var url = `reqFrom=CUSTOM`;
            try {
                const response = await locateBillingService.getClientList(url);
                vm.clientList = response.data.items || [];
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').value="";                
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').listOptions = vm.clientList;
            } catch (error) {
                vm.clientList = [];
                vm.leftSearchFields.find(f => f.fieldName === 'Contract').listOptions = [];
                console.error('Error fetching client list:', error);
            } finally {
                vm.isLoading = false;
            }
        },
        openSelectedRecords(payload) {
            this.isCopyRate = false;
            this.selectedRateIds = payload.ids.map(Number);
            this.isShownCopyButton = true;

            this.Headers.forEach(col => {
                if (
                    col.COLUMN_NAME === "New_Start_Date" ||
                    col.COLUMN_NAME === "New_End_Date" ||
                col.COLUMN_NAME === "New_Rate" ||
                //    col.COLUMN_NAME === "comment" ||
                col.COLUMN_NAME == "New_Customer_Work_Code"
                ) {
                    col.VISIBLE = true;
                }
        });
    

        this.RateScheduleData.forEach(row => {
            if (this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)) {

                row.New_Start_Date = payload.newStartDate
                    ? this.$options.filters.formatDate(payload.newStartDate)
                    : '--';

                row.New_End_Date = payload.newEndDate
                    ? this.$options.filters.formatDate(payload.newEndDate)
                    : '--';
                    row.New_Rate = row.AMOUNT;
                    row.New_Customer_Work_Code = row.Billing_Code;
                    row.action = payload.action || null;
            }
        });

        this.refreshKey++;

        this.$nextTick(() => {
                setTimeout(() => {
                    $('.left-search, .tg-left-search, .search-panel').hide();
                    $('table tbody tr').hide();
                    this.leftSearchFields=[]; 
                    this.TotalRecords=[];
                    $('.chkItems:checkbox').each(function () {
                        const id = Number($(this).val());
                        if (payload.ids.includes(id)) {
                            const row = $(this).closest('tr');
                            row.show();
                            row[0].scrollIntoView({
                                behavior: 'smooth',
                                block: 'center'
                            });
                        }
                    });
                }, 150);
            });
        },

        onSelectionChange(value, x) {
            var vm = this;
            vm.isLoading = true;
            if(x==null){
                 vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
            }
            vm.selectedId = x;
            var url = `clientId=${x}&configId=&reqFrom=&clientIds=`;            
            locateBillingService.getUtilityList(url).then(response => {
                vm.isLoading = false;
                let SelectedUtilityList = [];
                var UtilityList = response.data;
                if (UtilityList != null && UtilityList.length > 0) {
                    UtilityList.forEach(item => {
                        let obj = {
                            name: item.UTILITY_NAME,
                            value: item.UTILITY_NAME
                        };
                        SelectedUtilityList.push(obj);
                    });
                    vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = SelectedUtilityList;
                } else {
                    vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
                }
            }).catch(error => {
                vm.isLoading = false;
                vm.leftSearchFields.find(f => f.fieldName === 'UtilityName').listOptions = [];
            }).finally(() => {
                vm.isLoading = false;
            });
        },

        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case "Edit":
                    this.EditAddRate(item.RATE_SCHEDULE_ID);
                    break;
            }
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    const fvalue = value.searchConditionJson.split('=')[1];
                    this.Searchparms = fvalue;
                } else {
                    this.Searchparms='';
                    this.searchCondition = value.searchCondition;
                }
            }
            else {
                this.Searchparms='';
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Inactive":
                    this.UpdataStatus(1002, '');
                    break;
                case "AddRateSchedule":
                    this.AddRateSchedule();
                    break;
                case "Update":
                    this.BulkUpdateRate();
                    break;
                case "CopyRate":
                    this.CopyRate();
                    break;
                case "ExportToExcel":
                    this.ExportToExcel();
                    break;
                case "ViewHistory":
                    this.ViewHistory();
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
            }
        },
        UpdateCopyRateSchedule() {            
            if (!this.selectedRateIds || this.selectedRateIds.length === 0) {
                this.ShowAlert(this.$t("PleaseSelectAnyRecordsForFurther"),"warning",true,this.$t("Alert"));
                return;
            }            
            const selectedRows = this.RateScheduleData.filter(x =>
                this.selectedRateIds.includes(x.RATE_SCHEDULE_ID)
            );
            const utilityNames = [...new Set(selectedRows.map(row => row.UTILITY_NAME))];
            
            const jsonPayload = selectedRows.map(row => ({
                RateScheduleId: row.RATE_SCHEDULE_ID,
                ClientId: row.CLIENT_ID,
                WorkCodeId: row.WORKCODE_ID,
                UtilityId: row.UTILITY_ID,
                State: row.STATE_CODE,
                StartDate: row.New_Start_Date,
                EndDate: row.New_End_Date,
                Rate: row.New_Rate,
                //Comment: row.COMMENT || "",  
                Notes: row.NOTES || "",
                StatusId: row.STATUS_ID,
                optionselected: row.action,
                BillingCode:row.New_Customer_Work_Code,
                // OriginalStartDate: row.START_DATE,
                // OriginalEndDate: row.END_DATE,
                // OriginalRate: row.AMOUNT || row.RATE
            }));
            
            const params = {
                jsonString: JSON.stringify(jsonPayload),
                optionselected: jsonPayload[0].optionselected
            };            
            this.isLoading = true; 
                       
            DataService.UpdateRates(params).then(res => {
                    this.isLoading = false;                    
                    if (res && res.data) {
                        if (res.data.msg === '1') {
                            this.ShowAlert(this.$t("RecordUpdatedSuccessfully"),"success",true,this.$t("Alert"));
                            
                            this.RateScheduledeListing = this.RateScheduledeListing.filter(
                                row => !this.selectedRateIds.includes(row.RATE_SCHEDULE_ID)
                            );                            
                            this.selectedRateIds = [];
                            this.isShownCopyButton = false;
                            
                            this.Headers.forEach(col => {
                                if (
                                    col.COLUMN_NAME === "New_Start_Date" ||
                                    col.COLUMN_NAME === "New_End_Date" ||
                                    col.COLUMN_NAME === "New_Rate" ||
                                    col.COLUMN_NAME === "comment" ||
                                    col.COLUMN_NAME === "New_Customer_Work_Code"
                                ) {
                                    col.VISIBLE = false;
                                }
                            });
                            
                            this.FetchData();
                        } 
                        else if (res.data.result === '-3') {
                            const utilityList = utilityNames.join(', ');
                            this.ShowAlert(`Rate for utilities already exists please change the date range for following utilities: ${utilityList}`,
                                "alert-danger",true,"Date Overlap");
                        }
                        else if (res.data.result === '-2') {
                            this.ShowAlert(res.data.msg || "Rate for utilities already exists. Please change date range.",
                                "warning", true,"Utility Overlap");
                        }
                        else {
                            this.ShowAlert(res.data.msg || this.$t("UnknownError"),"failure",true,this.$t("Alert"));
                        }
                    } else {
                        this.ShowAlert(this.$t("UnknownError"),"failure",true,this.$t("Alert"));
                    }
                })
                .catch(error => {
                    this.isLoading = false;                                     
                    this.ShowAlert(this.$t("UnknownError"),"failure",true,this.$t("Alert"));
                });
        },
        Cancel(){            
            window.location.href = window.location.href;       
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    const fvalue = value.searchConditionJson.split('=')[1];
                    this.Searchparms = fvalue;
                } else {
                    this.Searchparms='';
                    this.searchCondition = value.searchCondition;
                }
            }
            else {
                this.Searchparms='';
                this.searchCondition = "";
            }
            this.FetchData();
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "Inactive":
                    this.UpdataStatus(1002, '');
                    break;
                case "AddRateSchedule":
                    this.AddRateSchedule();
                    break;
                case "Update":
                    this.BulkUpdateRate();
                    break;
                case "CopyRate":
                    this.CopyRate();
                    break;
                case "ExportToExcel":
                    this.ExportToExcel();
                    break;
                case "ViewHistory":
                    this.ViewHistory();
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
            }
        },
        CopyRate() {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
             if (val.length > 0) {
                     var vm = this;
                    vm.EditData =vm.RateScheduleData.filter(x => ids.includes(x.RATE_SCHEDULE_ID))
                    vm.isCopyRate = true;
                }
            else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }  
           
        },
        BulkUpdateRate () {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });
            let ids = val.split(',').map(Number);
             if (val.length > 0) {
                 vm.EditData = vm.RateScheduleData.filter(x => ids.includes(x.RATE_SCHEDULE_ID));
                 vm.isBulkUpdateRate = true;
            }
            else {
                vm.ShowAlert(vm.$t("PleaseSelectAnyRecordsForFurther"), "warning", true, vm.$t("Alert"));
            }           
        },
        AddRateSchedule () {
            var vm = this;
            vm.EditData =[];
            vm.isShowAddRate = true;
        },
        sortdata: function (sortBy) {
            this.SortBy = sortBy;
            var sortExp = 'ASC';
            if (this.SortExp == 'ASC') {
                sortExp = 'DESC';
            }
            this.SortExp = sortExp;
            this.SortBy = sortBy;
            this.SortExp = sortExp;
            this.PageNumber = 1;
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = {
                    ...actionItem
                };
                switch (action.title) {
                    case 'Edit':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        FetchData: async function () {
            var vm = this;
            vm.isCopy=false;
            vm.UpdateRecord=false;
            var params = '';
            vm.isLoading = true;          
             var params = `clientId=${vm.clientId}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&pageNum=${vm.PageNumber}&pageSize=${vm.PageSize}&Search=${vm.searchCondition}&userDate=${Date.now()}&BillerIds=${vm.Searchparms}`            
            await DataService.GetRateSechduleList(params).then((response) => {
                if (response.data.result.length > 0) {
                    vm.isLoading = false;
                    vm.RateScheduleData = JSON.parse(response.data.result);
                    vm.TotalRecords = vm.RateScheduleData[0].TOTAL_RECORDS;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;                   
                    vm.noRecords = false;
                } else {
                    vm.RateScheduleData = [];
                    vm.noRecords = true;
                    vm.TotalRecords = 0
                    vm.isLoading = false;
                }
            })
        },
         UpdataStatus(StatusID, ID) {
            var vm = this;
            var val = "";
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(async function () {
                if (val.length > 0) {
                    val += ',';
                }
                val += $(this).val();
            });

            vm.confirmR(vm.$t('ChanggingActivetoInactive'), true, false, function (result) {
                var postJSON = {
                    ID: val || ID,
                    StatusId: StatusID,
                    IsFor: "TALYGEN_BE_RATE_SCHEDULE",
                    Module: "RateSchedule",
                    Submodule: "Rate Schedule",
                };
                var objectPostString = JSON.stringify(postJSON);
                DataService.CommonUpdateStatus(objectPostString).then(async response => {
                    if (response.status == 200) {
                        $('.chkItems:checkbox:checked').prop("checked", false).removeAttr('checked');
                        vm.listheaderbuttons[0].isdisabled = true;                       
                        vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                        vm.FetchData();

                    }
                });
            })
        },
        commonDeleteData: function (id) {
            var vm = this;
            var val = "";
            vm.isLoading = true;
            if (id == null) {
                $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            } else {
                val = id;
            }
            if (val != null) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("RateSchedule")), function () {
                    var url = `ids=${val}&tablename=TALYGEN_BE_RATE_SCHEDULE&primaryKey=RATE_SCHEDULE_ID`;
                    DataService.Delete(url).then(function (response) {
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('RateSchedule')]), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('RateSchedule')]), "Success", true, vm.$t("Alert"));
                        }
                    });
                });
            } else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        },
        EditAddRate(id){
            var vm=this;
            if(vm.isCopy||vm.UpdateRecord){
                vm.EditDataCopy=vm.RateScheduleData[0];
                vm.isCopy=true;
                vm.isCopyRate = true;
            }else{
                 var vm=this;            
                vm.EditData = vm.RateScheduleData.find(x => x.RATE_SCHEDULE_ID === id);
                vm.isShowAddRate=true;
            }
           
        },
        ViewHistory() {
            var vm = this;
            this.$router.push({name:'RateScheduleHistory'});
        },

       handleChildSubmit(payload) {
            const vm = this;           
            if (!payload || !payload.CopyRate) return;
            const copyRate = payload.CopyRate;
            if(payload.formfields.PreviousRecords){
                vm.isCopy=true;
                vm.UpdateRecord=false;
            }else{
                vm.isCopy=false;
                vm.UpdateRecord=true;
            }
            const item = vm.RateScheduleData.find(r =>
                r.RATE_SCHEDULE_ID == copyRate.RateScheduleId &&
                r.CLIENT_ID == copyRate.ClientId
            );
            if (!item) return;
            const updatedRecord = {
                ...item,
                optionselected: vm.isCopy?'UPDATE_END_DATE':'MARK_AS_INACTIVE',
                AMOUNT: Number(copyRate.Rate),
                START_DATE: new Date(copyRate.StartDate).toLocaleDateString("en-US"),
                END_DATE: new Date(copyRate.EndDate).toLocaleDateString("en-US"),
                COMMENT: copyRate.Comment || item.COMMENT
            };          
            vm.RateScheduleData=[];
            vm.RateScheduleData[0]= updatedRecord;
        },

        onSubmit() {
            const vm = this;
            if (vm.RateScheduleData.length === 1) {
                const row = vm.RateScheduleData[0];

                // ✅ payload object (NOT a function)
                const payload = {
                    RateScheduleId: row.RATE_SCHEDULE_ID,
                    ClientId: row.CLIENT_ID,
                    UtilityId: row.UTILITY_ID,
                    WorkCodeId: row.WORKCODE_ID,
                    Rate: row.AMOUNT,
                    StartDate: row.START_DATE,
                    EndDate: row.END_DATE,
                    Comment: row.COMMENT,
                    BillingCode: row.Billing_Code,
                    optionselected: row.optionselected,

                    // extra fields (safe for OPENJSON)
                    State: row.STATE_CODE,
                    Notes: row.NOTES,
                    StatusId: row.STATUS_ID,
                    CreatedBy: row.CREATED_BY,
                    CreatedAt: row.CREATED_AT,
                    ModifiedBy: row.MODIFIED_BY,
                    ModifiedDate: row.MODIFIED_AT,
                    UtilityName: row.UTILITY_NAME,
                    ClientName: row.CLIENT_NAME,
                    WorkCode: row.WORK_CODE,
                    Status: row.STATUS
                };

                DataService.UpdateRateSchedule(payload).then(response => {
                    if (!response.data) return;
                    const result = response.data.RESULT ?? JSON.parse(response.data)[0]?.RESULT;
                    if (parseInt(result) === 1) {
                        vm.ShowAlert(vm.$t('UpdatedSuccess', [vm.$t('RateSchedule')]),"success",true,vm.$t('Alert'));
                        vm.FetchData();
                    } else {
                        vm.ShowAlert(vm.$t("UnknownError"), "failure", vm.$t('Alert'));
                    }
                });
            }
        },

        BindSupervisor:  function () {
            var vm = this;           
            DataService.CheckIsSupervisor().then(response => {
                if (response.data) {                      
                    vm.isSupervisor=response.data;
                }
            });
        },

        GetEmailConfigurationSetting() {
            var vm = this;
            var params = `_CompanyId=${vm.CompanyId}&userId=${vm.UserId}&moduleName=User&configkey=CanViewAllContractData`;
            DataService.GetEmailConfigurationSetting(params)
                .then(response => {
                    if (response.data && response.data.length > 0)
                    {
                        if(response.data[0].CONFIG_DATA_VALUE.toLowerCase() === 'yes' || vm.UserType.toLowerCase()=='ca' || vm.isSupervisor){                           
                            Schema.bindleftCommonSearchdropdown(this,"BILLER");                      
                        } else {
                            vm.leftSearchFields = vm.leftSearchFields.filter((_, index) => index !== 4);
                        }
                    }
                })
                .catch(err => {
                    console.log(err);
                });
        },
   

        async ExportToExcel() {
            var vm = this;
            vm.isLoading = true;        
            //await vm.FetchData();
            var objTemplate = {
                'Client Name': '',
                'Rate Schdule Id': '',
                'Work Code': '',
                'Utility Name': '',
                'Rate': '',
                'State': '', 
                'Start Date':'',
                'End Date':'',
                'Amount':'',
                'Notes':'',
                'Modified At':'',
                'Modified By':'',
                'Status':'',
                'Created At':'',
                'Created By':'',              
                'Billing Code':''
            };
            var dataArray = [];
            try {
                var RateScheduleArray = vm.RateScheduleData;
                RateScheduleArray.forEach(function (item) {
                    var newObj = Object.assign({}, objTemplate);
                    newObj['Client Name'] = item.CLIENT_NAME || '';
                    newObj['Rate Schdule Id'] = item.RATE_SCHEDULE_ID || '';
                    newObj['Work Code'] = item.WORK_CODE || '';
                    newObj['Utility Name'] = item.UTILITY_NAME || '';                   
                    newObj['Rate'] = item.AMOUNT || '';
                    newObj['State'] = item.STATE_NAME || '';
                    newObj['Start Date'] = item.START_DATE || '';
                    newObj['End Date'] = item.END_DATE || '';
                    newObj['Amount'] = item.AMOUNT || '';
                    newObj['Notes'] = item.NOTES || '';
                    newObj['Modified At'] = item.MODIFIED_AT || '';
                    newObj['Modified By'] = item.MODIFIED_BY || '';
                    newObj['Status'] = item.STATUS || '';
                    newObj['Created At'] = item.CREATED_AT || '';
                    newObj['Created By'] = item.CREATED_BY || '';
                    newObj['Billing Code'] = item.Billing_Code || '';                    
                    dataArray.push(newObj);
                });
            } catch (e) {
                console.error("Invalid JSON string in GetExcelListing:", e);
            }

            if (dataArray.length > 0) {           
                const worksheet = XLSX.utils.json_to_sheet([]);
                const workbook = XLSX.utils.book_new();
                const currentDateTime = new Date().toLocaleString('en-US');
                const titleRow = [
                    ['RateSchedule Report', '', '', '', currentDateTime] 
                ];
                XLSX.utils.sheet_add_aoa(worksheet, titleRow, { origin: 'A1' });
                worksheet['!merges'] = [
                    { s: { r: 0, c: 0 }, e: { r: 0, c: 3 } } 
                ];
                worksheet['A1'].s = {
                    font: { bold: true, size: 20, color: { rgb: "000000" } }, 
                    alignment: { horizontal: "left" },
                };
                worksheet['E1'].s = {
                    font: { bold: true, size: 20, color: { rgb: "000000" } },
                    alignment: { horizontal: "left" },
                };
                const header = Object.keys(dataArray[0]);
                XLSX.utils.sheet_add_aoa(worksheet, [header], { origin: 'A2' });
                XLSX.utils.sheet_add_json(worksheet, dataArray, { origin: 'A3', skipHeader: true });
                const range = XLSX.utils.decode_range(worksheet['!ref']);
                for (let C = range.s.c; C <= range.e.c; ++C) {
                    const cell_address = XLSX.utils.encode_cell({ c: C, r: 1 }); 
                    if (!worksheet[cell_address]) continue;
                    worksheet[cell_address].s = {
                        font: { bold: true, size: 18, color: { rgb: "000000" } }, 
                        fill: { fgColor: { rgb: "D3D3D3" } }, 
                        alignment: { horizontal: "left" },
                    };
                }
                const colWidths = header.map(col => ({
                    wpx: Math.max(
                        col.length * 10, 
                        ...dataArray.map(row => (row[col] || '').toString().length * 10) 
                    )
                }));
                worksheet['!cols'] = colWidths;
                XLSX.utils.book_append_sheet(workbook, worksheet, "RateSchedule List");
                XLSX.writeFile(workbook, "RateSchedule-List.xlsx");
            } else {
                console.error("No data available to export");
            }
            vm.isLoading = false;
        },
    }
}
